const raw = $input.first().json;
const rows = Array.isArray(raw) ? raw : [];
if (rows.length === 0) return [{ json: { _empty: true, count: 0 } }];
// Aggregate per advisor + per principal.
const byAdvisor = {};
const byPrincipal = {};
const ids = [];
for (const r of rows) {
  ids.push(r.id);
  const a = r.advisor_id;
  if (a) {
    if (!byAdvisor[a]) byAdvisor[a] = { advisor_id: a, total_advisor_cents: 0, count: 0 };
    byAdvisor[a].total_advisor_cents += parseInt(r.advisor_commission) || 0;
    byAdvisor[a].count += 1;
  }
  const p = r.mga_principal_id;
  if (p) {
    if (!byPrincipal[p]) byPrincipal[p] = { mga_principal_id: p, total_mga_cents: 0, count: 0 };
    byPrincipal[p].total_mga_cents += parseInt(r.mga_commission) || 0;
    byPrincipal[p].count += 1;
  }
}
// CSV summary for Mary (Phase 5 manual execution).
const csv = ['ledger_id,advisor_id,carrier_name,product_type,policy_number,advisor_commission_cents,mga_commission_cents,carrier_commission_cents'].concat(rows.map(function (r) {
  return [r.id, r.advisor_id, (r.carrier_name||'').replace(/,/g,';'), r.product_type||'', r.policy_number||'', r.advisor_commission||0, r.mga_commission||0, r.carrier_commission||0].join(',');
})).join('\n');
return [{ json: { _ready: true, ledger_ids: ids, count: rows.length, by_advisor: Object.values(byAdvisor), by_principal: Object.values(byPrincipal), csv: csv, run_at: new Date().toISOString() } }];

const ids = $('Aggregate').first().json.ledger_ids || [];
const page = $('Batch Mark').context.currentRunIndex || 0;
const pageSize = 50;
const chunk = ids.slice(page * pageSize, (page + 1) * pageSize);
if (chunk.length === 0) return [{ json: { _done: true } }];
return chunk.map(function (id) { return { json: { ledger_id: id } }; });
